import{_ as l,o as i,c as e,ag as n}from"./chunks/framework.BY_wD62d.js";const b=JSON.parse('{"title":"路线图","description":"","frontmatter":{"_rawMarkdown":"# 路线图\\n\\n本文档概述 OpenViking 的开发路线图。\\n\\n## 已完成功能\\n\\n### 核心基础设施\\n- 三层信息模型（L0/L1/L2）\\n- Viking URI 寻址系统\\n- 双层存储（AGFS + 向量索引）\\n- 异步/同步客户端支持\\n\\n### 资源管理\\n- 文本资源管理（Markdown、HTML、PDF）\\n- 自动 L0/L1 生成\\n- 带向量索引的语义搜索\\n- 资源关联和链接\\n\\n### 检索\\n- 基本语义搜索（`find`）\\n- 带意图分析的上下文感知搜索（`search`）\\n- 基于会话的查询扩展\\n- 重排序流水线\\n\\n### 会话管理\\n- 对话状态追踪\\n- 上下文和技能使用追踪\\n- 自动记忆提取\\n- 使用 LLM 的记忆去重\\n- 会话归档和压缩\\n\\n### 技能\\n- 技能定义和存储\\n- MCP 工具自动转换\\n- 技能搜索和检索\\n\\n### 配置\\n- 可插拔的 Embedding 提供者\\n- 可插拔的 LLM 提供者\\n- 基于 YAML 的配置\\n\\n### Server & Client 架构\\n- HTTP Server (FastAPI)\\n- Python HTTP Client\\n- API Key 认证\\n- 客户端抽象层（LocalClient / HTTPClient）\\n\\n---\\n\\n## 未来计划\\n\\n### CLI\\n- 完整的命令行界面，支持所有操作\\n- 分布式存储后端\\n\\n### 多模态支持\\n- 支持图像、视频、音频等多模态资源的智能解析和访问\\n- 多模态资源的目录存储结构\\n\\n### 上下文管理\\n- 上下文修改对上层的传导更新\\n- 支持对上下文的版本管理和回滚 (参考 git) \\n\\n### 资源节点的权限控制\\n- 支持多Agent / 多User 使用\\n- 不同角色的隔离设计\\n- 资源目录节点的访问控制和权限设计\\n\\n### 生态集成\\n- 流行 Agent 框架适配\\n- 插件系统，支持自定义组件\\n\\n欢迎在 issue 中提出建议和反馈。\\n---\\n\\n## 贡献\\n\\n我们欢迎贡献以帮助实现这些目标。请参阅 [贡献指南](contributing.md)。\\n"},"headers":[],"relativePath":"zh/about/03-roadmap.md","filePath":"zh/about/03-roadmap.md","lastUpdated":1770642735000}'),r={name:"zh/about/03-roadmap.md"};function t(o,a,h,d,u,s){return i(),e("div",null,[...a[0]||(a[0]=[n("",32)])])}const P=l(r,[["render",t]]);export{b as __pageData,P as default};
